module top_module(misleading_ledIn, ledGreen, ledRed);input [3:0] misleading_ledIn;
  output ledGreen, ledRed;
  reg ledGreen, ledRed;

  always @ (misleading_ledIn)
  begin
    if(misleading_ledIn == 4'b1111)
      begin
	ledGreen  = 1;
	ledRed = 0;
      end
    else
      begin
	ledGreen  = 0;
	ledRed = 1;
      end
  end

endmodule
